LEGACY_HTML = True  # 既存HTMLを保持（再アセンブル禁止）
TITLE = '健診結果の見方【無料】血液検査・健康診断の数値を解説'
DESCRIPTION = '健康診断・血液検査の結果数値の意味を分かりやすく解説。気になる項目の改善方法も提案。'
JS_CODE = 'function evaluate(val, low, highNormal, highCaution, unit, name) {\n      if (val === null || isNaN(val)) return null;\n      let status, color, icon, advice;\n      if (val < low) { status=\'低値\'; color=\'text-blue-600\'; icon=\'⬇️\'; advice=`${name}が基準より低い値です。医師に相談を。`; }\n      else if (val <= highNormal) { status=\'正常\'; color=\'text-green-600\'; icon=\'✅\'; advice=`${name}は正常範囲内です。この状態を維持しましょう。`; }\n      else if (val <= highCaution) { status=\'要注意\'; color=\'text-yellow-600\'; icon=\'⚠️\'; advice=`${name}がやや高めです。生活習慣の見直しを検討しましょう。`; }\n      else { status=\'要改善\'; color=\'text-red-600\'; icon=\'🚨\'; advice=`${name}が基準値を超えています。医師への相談を強くお勧めします。`; }\n      return { val, unit, name, status, color, icon, advice };\n    }\n\n    function showResult() {\n      const sbp = parseFloat(document.getElementById(\'sbp\').value) || null;\n      const dbp = parseFloat(document.getElementById(\'dbp\').value) || null;\n      const glucose = parseFloat(document.getElementById(\'glucose\').value) || null;\n      const hba1c = parseFloat(document.getElementById(\'hba1c\').value) || null;\n      const ldl = parseFloat(document.getElementById(\'ldl\').value) || null;\n      const hdl = parseFloat(document.getElementById(\'hdl\').value) || null;\n      const alt = parseFloat(document.getElementById(\'alt\').value) || null;\n      const bmi = parseFloat(document.getElementById(\'bmi\').value) || null;\n\n      const results = [\n        evaluate(sbp, 70, 129, 139, \'mmHg\', \'収縮期血圧（上）\'),\n        evaluate(dbp, 40, 84, 89, \'mmHg\', \'拡張期血圧（下）\'),\n        evaluate(glucose, 50, 99, 109, \'mg/dL\', \'空腹時血糖\'),\n        evaluate(hba1c, 3.5, 5.5, 5.9, \'%\', \'HbA1c\'),\n        evaluate(ldl, 60, 139, 159, \'mg/dL\', \'LDLコレステロール\'),\n        hdl ? (hdl < 40 ? { val:hdl, unit:\'mg/dL\', name:\'HDLコレステロール\', status:\'低値\', color:\'text-red-600\', icon:\'🚨\', advice:\'HDL（善玉）コレステロールが低い。運動・禁煙が有効。\' } : hdl <= 80 ? { val:hdl, unit:\'mg/dL\', name:\'HDLコレステロール\', status:\'正常\', color:\'text-green-600\', icon:\'✅\', advice:\'HDLコレステロールは良好です。\' } : { val:hdl, unit:\'mg/dL\', name:\'HDLコレステロール\', status:\'良好\', color:\'text-green-600\', icon:\'✅\', advice:\'HDL（善玉）コレステロールが高く、動脈硬化リスクが低い状態です。\' }) : null,\n        evaluate(alt, 5, 30, 50, \'U/L\', \'ALT(GPT)\'),\n        bmi ? (bmi < 18.5 ? { val:bmi, unit:\'\', name:\'BMI\', status:\'低体重\', color:\'text-blue-600\', icon:\'⬇️\', advice:\'BMIが低体重域です。栄養バランスの見直しを。\' } : bmi <= 24.9 ? { val:bmi, unit:\'\', name:\'BMI\', status:\'標準\', color:\'text-green-600\', icon:\'✅\', advice:\'BMIは標準範囲。理想的な体重を維持しています。\' } : bmi <= 29.9 ? { val:bmi, unit:\'\', name:\'BMI\', status:\'過体重\', color:\'text-yellow-600\', icon:\'⚠️\', advice:\'BMIが過体重域。適度な運動と食事管理を。\' } : { val:bmi, unit:\'\', name:\'BMI\', status:\'肥満\', color:\'text-red-600\', icon:\'🚨\', advice:\'BMIが肥満域。生活習慣病リスクが高まっています。医師に相談を。\' }) : null\n      ].filter(r => r !== null);\n\n      if (results.length === 0) {\n        alert(\'少なくとも1つの数値を入力してください\');\n        return;\n      }\n\n      document.getElementById(\'form-section\').classList.add(\'hidden\');\n      document.getElementById(\'result-section\').classList.remove(\'hidden\');\n\n      const abnormal = results.filter(r => r.status === \'要改善\' || r.status === \'低値\');\n      const caution = results.filter(r => r.status === \'要注意\');\n      const normal = results.filter(r => r.status === \'正常\' || r.status === \'標準\' || r.status === \'良好\');\n\n      let summaryColor = abnormal.length > 0 ? \'bg-red-50 border-red-400\' : caution.length > 0 ? \'bg-yellow-50 border-yellow-400\' : \'bg-green-50 border-green-400\';\n      let summaryIcon = abnormal.length > 0 ? \'🚨\' : caution.length > 0 ? \'⚠️\' : \'✅\';\n      let summaryText = abnormal.length > 0 ? `${abnormal.length}項目に要改善・異常値があります` : caution.length > 0 ? `${caution.length}項目が要注意レベルです` : \'入力された数値はすべて正常範囲内です\';\n\n      let html = `\n        <div class="border-2 ${summaryColor} rounded-xl p-4 mb-6 text-center">\n          <div class="text-3xl mb-1">${summaryIcon}</div>\n          <p class="font-bold text-lg">${summaryText}</p>\n          <p class="text-sm text-gray-600 mt-1">入力値: ${results.length}項目 / 正常: ${normal.length} / 要注意: ${caution.length} / 要改善: ${abnormal.length}</p>\n        </div>\n'
MAIN_HTML = '<div><button class="btn">開始する</button></div>'
